sql:
SELECT AVG(height) AS average_height, AVG(weight) AS average_weight
FROM players
WHERE team = 'Collingwood';

external_knowledge:
- 'their own castles' refers to the home teams (team1);
- 'wandering opponents' refers to the away teams (team2);
- 'victors in their own castles' means the team with a higher score in their home ground (team1_score > team2_score);
- 'mightiest conquerors to the more modest' indicates the order from highest to lowest based on the home team's score.

sql:
SELECT year, start_date, end_date
FROM seasons
ORDER BY year ASC;

external_knowledge:
- "tall and light" refers to players taller than 185 cm and weighing less than 80 kg;
- "top shape" indicates that the athletes must be healthy without any injury status;
- "not too long ago" means the teams were established after the year 1900;
- "played for more than a few games" implies more than 5 matches played.

sql:
SELECT players.name, teams.team_name
FROM players
JOIN teams ON players.team = teams.team_name;

external_knowledge:
- "squad" refers to the team;
- "recent season" refers to the year 2019 in this context;
- "take part in a game" means actively participating in matches as either team1 or team2.

- 'Sailed under the banner' is a metaphor for 'played for the team'.;
- 'Crossed the river with a score over ten' refers to achieving a score higher than 10 points in a match.;
- 'Fierce naval battle' metaphorically represents a competitive match in the sport.
